#!/usr/bin/env node

const { execSync } = require('child_process');

function run(cmd) {
  console.log(`Running: ${cmd}`);
  try {
    execSync(cmd, { stdio: 'inherit' });
  } catch (error) {
    console.error(`Error running: ${cmd}`);
    console.error(error);
    process.exit(1);
  }
}

// Install dependencies
run('npm install');

// Run tests
run('npm test');

// Build the application
run('npm run build');

